import (
	"io"
	"net"
	"net/http"
	"net/url"
	"time"

	"github.com/gofiber/fiber/v2"
)

// webhookRequest represents the expected JSON request body
type webhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// ConfigureWebhook handles POST requests to configure a webhook URL.
// It validates the URL, ensures it points to a publicly reachable host,
// sends a GET request to test it, limits response size, and saves the configuration.
func ConfigureWebhook(ctx *fiber.Ctx) error {
	var req webhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid JSON format",
		})
	}

	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url is required",
		})
	}

	parsedURL, err := url.Parse(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid webhook URL format",
		})
	}

	// Only allow http or https schemes
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook URL must use http or https scheme",
		})
	}

	// Reject URLs containing user info (e.g., user:password@host)
	if parsedURL.User != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook URL must not contain user info",
		})
	}

	host := parsedURL.Hostname()
	if host == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook URL must contain a valid host",
		})
	}

	// Ensure the target host resolves to a public IP address
	if !isHostAllowed(host) {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook URL must point to a publicly reachable address",
		})
	}

	// Build a custom HTTP client with a short timeout, limited redirects,
	// and disabled keep‑alive to reduce resource usage.
	client := &http.Client{
		Timeout: 3 * time.Second,
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			// Allow at most one redirect to avoid open‑redirect abuse
			if len(via) >= 1 {
				return http.ErrUseLastResponse
			}
			return nil
		},
		Transport: &http.Transport{
			DisableKeepAlives: true,
		},
	}

	// Send a GET request to test the webhook URL (no body)
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Failed to reach webhook URL",
		})
	}

	// Limit reading the response body to 1 MB to prevent memory exhaustion
	defer resp.Body.Close()
	_, _ = io.Copy(io.Discard, io.LimitReader(resp.Body, 1<<20))

	// Verify that the webhook responded with a 2xx status code
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Webhook URL returned non‑success status",
		})
	}

	// Save the webhook configuration (e.g., db.SaveWebhookURL(req.WebhookURL))
	// ...

	// Return a success response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success": true,
		"message": "Webhook configured successfully",
	})
}

// isHostAllowed checks whether the given host resolves to a public IP address.
// It rejects loopback, link‑local, unspecified, multicast, and private IP ranges.
func isHostAllowed(host string) bool {
	// Try to parse the host as an IP address directly
	ip := net.ParseIP(host)
	if ip != nil {
		return isPublicIP(ip)
	}

	// Resolve the hostname and check each resolved address
	addrs, err := net.LookupHost(host)
	if err != nil {
		// If resolution fails we treat the host as unsafe
		return false
	}
	for _, addr := range addrs {
		ip = net.ParseIP(addr)
		if ip == nil {
			continue
		}
		if !isPublicIP(ip) {
			return false
		}
	}
	return true
}

// isPublicIP returns true if the IP is considered public (not private, loopback, etc.)
func isPublicIP(ip net.IP) bool {
	if ip.IsLoopback() || ip.IsUnspecified() || ip.IsLinkLocalUnicast() || ip.IsMulticast() {
		return false
	}
	// Check IPv4 private ranges
	if ip4 := ip.To4(); ip4 != nil {
		// 10.0.0.0/8
		if ip4[0] == 10 {
			return false
		}
		// 172.16.0.0/12
		if ip4[0] == 172 && ip4[1] >= 16 && ip4[1] <= 31 {
			return false
		}
		// 192.168.0.0/16
		if ip4[0] == 192 && ip4[1] == 168 {
			return false
		}
	}
	// IPv6 private ranges (fc00::/7) and link‑local (fe80::/10) are already
	// covered by the earlier checks (IsLinkLocalUnicast). Additional IPv6
	// private range filtering can be added here if desired.
	return true
}

// main sets up the Fiber router and starts the HTTP server.
