		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid JSON body",
		})
	}

	// Validate webhook_url is provided
	if body.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url is required",
		})
	}

	// Create HTTP client with 3 second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Validate webhook URL by sending a test GET request
	testReq, err := http.NewRequest(http.MethodGet, body.WebhookURL, nil)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid webhook URL format",
		})
	}

	// Send test request
	resp, err := client.Do(testReq)
	if err != nil {
		// Log the error but continue with saving (webhook might be temporarily unavailable)
		log.Printf("Warning: Test request to webhook failed: %v", err)
		return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
			"success":       true,
			"message":       "Webhook URL configured but test request failed",
			"webhook_url":   body.WebhookURL,
			"test_result":   "failed",
			"test_error":    err.Error(),
		})
	}
	defer resp.Body.Close()

	// Save the configuration
	webhookURL = body.WebhookURL

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success":     true,
		"message":     "Webhook configured successfully",
		"webhook_url": webhookURL,
		"test_result": "success",
	})
}

func main() {
	// Create new Fiber app
	app := fiber.New()

	// POST endpoint for configuring webhook
	app.Post("/webhook/configure", ConfigureWebhook)

	// Health check endpoint
	app.Get("/", func(ctx *fiber.Ctx) error {
		return ctx.SendString("Server is running")
	})

	// Start server on port 3000
	fmt.Println("Starting Fiber server on :3000")
	log.Fatal(app.Listen(":3000"))
}

