package main

import (
	"log"
	"net/http"
	"time"

	"github.com/gofiber/fiber/v2"
)

// Global variable to store the configured webhook URL (in‑memory persistence).
var webhookURL string

// ConfigureWebhook handles POST requests containing a JSON body with a
// "webhook_url" field. It validates the URL by sending a GET request with a
// 3‑second timeout, saves the configuration, and returns a JSON response.
func ConfigureWebhook(ctx *fiber.Ctx) error {
	type requestBody struct {
		WebhookURL string `json:"webhook_url"`
	}

	var req requestBody
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": "Invalid JSON body",
		})
	}

	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": "webhook_url is required",
		})
	}

	// Validate the webhook URL by sending a GET request with a 3‑second timeout.
	client := &http.Client{
		Timeout: 3 * time.Second,
	}
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": "Failed to validate webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Optionally verify a non‑2xx status code.
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": "Webhook URL returned non‑2xx status: " + resp.Status,
		})
	}

	// Save the configuration (in‑memory).
	webhookURL = req.WebhookURL

	return ctx.JSON(fiber.Map{
		"success": true,
		"message": "Webhook configured successfully",
	})
}

func main() {
	// Initialize a new Fiber app.
	app := fiber.New()

	// Register the webhook configuration endpoint.
	app.Post("/webhook", ConfigureWebhook)

	// Start the server on port 3000.
	log.Fatal(app.Listen(":3000"))
}

