			"success": false,
			"error":   "Unable to resolve webhook hostname",
		})
	}

	// Verify that none of the resolved IPs are private/loopback
	for _, ip := range ips {
		// IPv4 or IPv6
		if ip.IsLoopback() || ip.IsPrivate() || ip.IsLinkLocalUnicast() || ip.IsUnspecified() {
