package main

import (
	"fmt"
	"net/http"
	"net/url"
	"time"

	"github.com/gofiber/fiber/v2"
)

// config holds the webhook configuration in memory.
var config struct {
	URL string
}

// ConfigureWebhook handles POST requests that contain a JSON body
// with the field "webhook_url". It validates the URL by performing a
// GET request with a 3‑second timeout, and if successful saves the URL.
// A JSON response is returned indicating the outcome.
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Structure expected in the request body.
	type reqBody struct {
		WebhookURL string `json:"webhook_url"`
	}

	var req reqBody
	// Parse JSON body.
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": "Invalid request body",
		})
	}

	// Validate presence of webhook_url.
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": "webhook_url is required",
		})
	}

	// Validate URL format (must be absolute and have http/https scheme).
	parsedURL, err := url.Parse(req.WebhookURL)
	if err != nil || parsedURL.Scheme == "" || parsedURL.Host == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": "Invalid webhook_url format",
		})
	}
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": "URL must use http or https scheme",
		})
	}

	// Create HTTP client with a 3‑second timeout.
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send a test GET request to the webhook URL.
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusInternalServerError).JSON(fiber.Map{
			"success": false,
			"message": "Failed to reach webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Consider any 2xx response as a successful validation.
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadGateway).JSON(fiber.Map{
			"success": false,
			"message": fmt.Sprintf("Webhook URL returned non‑2xx status: %d", resp.StatusCode),
		})
	}

	// Save the configuration.
	config.URL = req.WebhookURL

	// Return a success JSON response.
	return ctx.JSON(fiber.Map{
		"success":    true,
		"message":    "Webhook configured successfully",
		"webhook_url": config.URL,
	})
}

func main() {
	// Initialize a new Fiber application.
	app := fiber.New()

	// Define the route that triggers the handler.
	app.Post("/webhook", ConfigureWebhook)

	// Start the HTTP server on port 8080.
	if err := app.Listen(":8080"); err != nil {
		panic(err)
	}
}

