package main

import (
	"log"
	"net/http"
	"net/url"
	"time"

	"github.com/gofiber/fiber/v2"
)

// WebhookConfig represents the request body.
type WebhookConfig struct {
	WebhookURL string `json:"webhook_url"`
}

// Response represents the JSON response.
type Response struct {
	Success bool   `json:"success"`
	Message string `json:"message,omitempty"`
}

// storedWebhookURL holds the currently configured webhook URL in memory.
var storedWebhookURL string

// ConfigureWebhook handles POST requests with a webhook_url and validates it.
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse request body
	var cfg WebhookConfig
	if err := ctx.BodyParser(&cfg); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "Invalid request body",
		})
	}

	// Validate the provided URL
	parsedURL, err := url.Parse(cfg.WebhookURL)
	if err != nil || parsedURL.Scheme == "" || parsedURL.Host == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "Invalid URL format",
		})
	}

	// Only allow http and https schemes
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "URL must use http or https scheme",
		})
	}

	// Create HTTP client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send GET request to validate the webhook URL
	resp, err := client.Get(cfg.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadGateway).JSON(Response{
			Success: false,
			Message: "Failed to reach webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Check status code
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadGateway).JSON(Response{
			Success: false,
			Message: "Webhook URL returned non-2xx status: " + resp.Status,
		})
	}

	// Save the configuration (in-memory)
	storedWebhookURL = cfg.WebhookURL

	return ctx.JSON(Response{
		Success: true,
		Message: "Webhook URL configured successfully",
	})
}

func main() {
	app := fiber.New()

	// Endpoint to configure the webhook
	app.Post("/webhook", ConfigureWebhook)

	// Start server on port 3000
	log.Fatal(app.Listen(":3000"))
}

