// webhookRequest represents the expected JSON request body.
type webhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// webhookTestPayload is the payload sent to test the webhook (not used for GET).
type webhookTestPayload struct {
	Message string `json:"message"`
}

// isPrivateIP checks if an IP address is private or loopback.
// It supports IPv4 and IPv6.
func isPrivateIP(ipStr string) bool {
	ip := net.ParseIP(ipStr)
	if ip == nil {
		return false
	}
	// Loopback
	if ip.IsLoopback() {
		return true
	}
	// IPv4 private ranges
	if ip4 := ip.To4(); ip4 != nil {
		// 10.0.0.0/8
		if ip4[0] == 10 {
			return true
		}
		// 172.16.0.0/12
		if ip4[0] == 172 && ip4[1] >= 16 && ip4[1] <= 31 {
			return true
		}
		// 192.168.0.0/16
		if ip4[0] == 192 && ip4[1] == 168 {
			return true
		}
		return false
	}
	// IPv6 private ranges (fc00::/7)
	if ip.IsUnspecified() {
		return true
	}
	// Link‑local
	if ip.IsLinkLocalUnicast() {
		return true
	}
	// Unique local addresses (fc00::/7)
	if ip[0]&0xfe == 0xfc {
		return true
	}
	return false
}

// resolveAndCheckPrivate checks if the host resolves to a private IP.
// It returns true if any resolved address is private (indicating the URL points to internal resources).
func resolveAndCheckPrivate(host string) bool {
	// If host is already an IP, check directly
	if ip := net.ParseIP(host); ip != nil {
		return isPrivateIP(ip.String())
	}
	// Attempt DNS resolution
	addrs, err := net.LookupHost(host)
	if err != nil {
		// If resolution fails we treat it as safe (no private IP)
		return false
	}
	for _, addr := range addrs {
		if isPrivateIP(addr) {
			return true
		}
	}
	return false
}

// ConfigureWebhook handles POST requests to configure a webhook URL.
// It validates that the URL is publicly reachable and then saves the configuration.
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse the JSON request body
	var req webhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid JSON format",
		})
	}

	// Validate that webhook_url is provided
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url is required",
		})
	}

	// Validate URL format
	parsedURL, err := url.ParseRequestURI(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid webhook URL format",
		})
	}

	// Ensure the URL uses a valid scheme
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook URL must use http or https scheme",
		})
	}

	// Disallow userinfo (e.g., http://user:pass@example.com) to prevent credential leakage
	if parsedURL.User != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook URL must not contain userinfo",
		})
	}

	// Host must be present
	if parsedURL.Host == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook URL must include a host",
		})
	}

	// SSRF protection: block private / internal IP addresses
	if resolveAndCheckPrivate(parsedURL.Host) {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook URL points to an internal or private network",
		})
	}

	// Create a custom HTTP client with a timeout and disable automatic redirects
	client := &http.Client{
		Timeout: 5 * time.Second,
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			// Do not follow redirects – prevents leaking internal IPs via Location header
			return http.ErrUseLastResponse
		},
	}

	// Build the test GET request
	testURL := req.WebhookURL
	// Append a harmless query param to identify this as a test
	if strings.Contains(testURL, "?") {
		testURL += "&_test=1"
	} else {
		testURL += "?_test=1"
	}
	reqGET, err := http.NewRequestWithContext(context.Background(), http.MethodGet, testURL, nil)
	if err != nil {
		return ctx.Status(fiber.StatusInternalServerError).JSON(fiber.Map{
			"success": false,
			"error":   "Failed to create test request",
		})
	}
	reqGET.Header.Set("User-Agent", "WebhookValidator/1.0")

	// Send the test GET request
	resp, err := client.Do(reqGET)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Failed to send test request to webhook URL: %v", err),
		})
	}
	defer resp.Body.Close()

	// Verify the webhook responded with a 2xx status code
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Webhook URL returned non-success status: %d", resp.StatusCode),
		})
	}

	// Save the configuration (stub)
	// db.SaveWebhookURL(req.WebhookURL)

	// Return a successful JSON response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success": true,
		"message": "Webhook configured successfully",
	})
}

