package main

import (
	"log"
	"net/http"
	"net/url"
	"sync"
	"time"

	"github.com/gofiber/fiber/v2"
)

// WebhookRequest represents the JSON body of the POST request.
type WebhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// cfg stores the currently configured webhook.
var (
	cfg      WebhookRequest
	cfgMutex sync.Mutex
)

// ConfigureWebhook handles the POST request to configure a webhook.
// It validates the supplied URL by performing a GET request with a 3‑second timeout,
// then saves the configuration.
func ConfigureWebhook(ctx *fiber.Ctx) error {
	var req WebhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid JSON body",
		})
	}

	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url is required",
		})
	}

	parsedURL, err := url.Parse(req.WebhookURL)
	if err != nil || parsedURL.Scheme == "" || parsedURL.Host == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid webhook URL",
		})
	}

	httpClient := &http.Client{
		Timeout: 3 * time.Second,
	}

	testReq, err := http.NewRequest(http.MethodGet, req.WebhookURL, nil)
	if err != nil {
		return ctx.Status(fiber.StatusInternalServerError).JSON(fiber.Map{
			"success": false,
			"error":   "Failed to create request",
		})
	}

	resp, err := httpClient.Do(testReq)
	if err != nil {
		return ctx.Status(fiber.StatusBadGateway).JSON(fiber.Map{
			"success": false,
			"error":   "Failed to reach webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadGateway).JSON(fiber.Map{
			"success": false,
			"error":   "Webhook URL returned non‑2xx status: " + resp.Status,
		})
	}

	cfgMutex.Lock()
	cfg = req
	cfgMutex.Unlock()

	return ctx.JSON(fiber.Map{
		"success": true,
		"message": "Webhook configured and validated successfully",
	})
}

func main() {
	app := fiber.New()

	app.Post("/webhook", ConfigureWebhook)

	log.Fatal(app.Listen(":3000"))
}

