package main

import (
	"log"
	"net/http"
	"time"

	"github.com/gofiber/fiber/v2"
)

// RequestBody represents the JSON body for configuring a webhook.
type RequestBody struct {
	WebhookURL string `json:"webhook_url"`
}

// Response represents the JSON response from ConfigureWebhook.
type Response struct {
	Success bool   `json:"success"`
	Message string `json:"message"`
}

// Global config to store the webhook URL (in‑memory)
var webhookURL string

// ConfigureWebhook handles POST requests to configure a webhook URL.
// It validates the URL by sending a GET request with a 3‑second timeout,
// saves the configuration, and returns a JSON result.
func ConfigureWebhook(ctx *fiber.Ctx) error {
	var req RequestBody
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "Invalid request body",
		})
	}

	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "webhook_url is required",
		})
	}

	// Create HTTP client with 3‑second timeout for the test request
	httpClient := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Validate the webhook URL by performing a GET request
	resp, err := httpClient.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "Failed to reach webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Consider 2xx status codes as successful
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "Webhook URL returned non‑2xx status: " + resp.Status,
		})
	}

	// Save configuration (in‑memory)
	webhookURL = req.WebhookURL

	// Return success response
	return ctx.JSON(Response{
		Success: true,
		Message: "Webhook URL configured successfully",
	})
}

func main() {
	// Initialize Fiber app
	app := fiber.New()

	// Register the webhook configuration endpoint
	app.Post("/webhook", ConfigureWebhook)

	// Start server on port 3000
	log.Fatal(app.Listen(":3000"))
}

