// isPrivateIP checks if an IP address is private
func isPrivateIP(ip net.IP) bool {
	privateIPBlocks := []*net.IPNet{
		parseCIDR("10.0.0.0/8"),
		parseCIDR("172.16.0.0/12"),
		parseCIDR("192.168.0.0/16"),
		parseCIDR("127.0.0.0/8"),
		parseCIDR("169.254.0.0/16"), // Link-local
		parseCIDR("fc00::/7"),       // IPv6 private range
		parseCIDR("fe80::/10"),      // IPv6 link-local
	}

	for _, block := range privateIPBlocks {
		if block != nil && block.Contains(ip) {
			return true
		}
	}
	return false
}

func parseCIDR(cidr string) *net.IPNet {
	_, ipNet, _ := net.ParseCIDR(cidr)
	return ipNet
}

// validateWebhookURL checks for SSRF vulnerabilities
func validateWebhookURL(webhookURL string) error {
	parsedURL, err := url.Parse(webhookURL)
	if err != nil {
		return fmt.Errorf("invalid URL format: %w", err)
	}

	// Only allow http and https schemes
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return fmt.Errorf("webhook URL must use http or https scheme")
	}

	// Get the hostname
	host := parsedURL.Hostname()
	if host == "" {
		return fmt.Errorf("webhook URL must have a valid host")
	}

	// Block localhost and similar localhost aliases
	localhostNames := []string{"localhost", "localhost.localdomain", "0.0.0.0", "::1"}
	for _, name := range localhostNames {
		if strings.EqualFold(host, name) {
			return fmt.Errorf("webhook URL cannot point to localhost")
		}
	}

	// Resolve hostname to IP addresses
	ips, err := net.LookupIP(host)
	if err != nil {
		return fmt.Errorf("failed to resolve webhook URL hostname: %w", err)
	}

	if len(ips) == 0 {
		return fmt.Errorf("no IP addresses found for webhook URL")
	}

	// Check if any resolved IP is private or internal
	for _, ip := range ips {
		if isPrivateIP(ip) {
			return fmt.Errorf("webhook URL cannot point to private or internal IP addresses")
		}
	}

	return nil
}

// ConfigureWebhook handles POST requests to configure a webhook URL
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse the JSON request body
	var req webhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid JSON format",
		})
	}

	// Validate that webhook_url is provided
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url is required",
		})
	}

	// Validate URL format
	parsedURL, err := url.ParseRequestURI(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid webhook URL format",
		})
	}

	// Ensure the URL has a valid scheme
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook URL must use http or https scheme",
		})
	}

	// SSRF Protection: Validate against private/internal IPs
	if err := validateWebhookURL(req.WebhookURL); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Webhook URL validation failed: %v", err),
		})
	}

	// Create a custom HTTP client with timeout and redirect limits for security
	client := &http.Client{
		Timeout: 3 * time.Second,
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			// Limit redirects to prevent open redirect vulnerabilities
			if len(via) >= 5 {
				return fmt.Errorf("too many redirects")
			}
			return nil
		},
	}

	// Prepare test payload (for GET request, we don't need body but keep for reference)
	testPayload := webhookTestPayload{
		Message: "Webhook configuration test",
	}
	jsonPayload, err := json.Marshal(testPayload)
	if err != nil {
		return ctx.Status(fiber.StatusInternalServerError).JSON(fiber.Map{
			"success": false,
			"error":   "Failed to create test payload",
		})
	}

	// Send GET request to webhook URL as per requirements
	httpReq, err := http.NewRequest(http.MethodGet, req.WebhookURL, bytes.NewBuffer(jsonPayload))
	if err != nil {
		return ctx.Status(fiber.StatusInternalServerError).JSON(fiber.Map{
			"success": false,
			"error":   "Failed to create request",
		})
	}
	httpReq.Header.Set("Content-Type", "application/json")

	resp, err := client.Do(httpReq)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Failed to send test request to webhook URL: %v", err),
		})
	}
	defer resp.Body.Close()

	// Check if the webhook responded successfully (2xx status)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Webhook URL returned non-success status: %d", resp.StatusCode),
		})
	}

	// Save the configuration
