package main

import (
	"encoding/json"
	"fmt"
	"log"
	"net/http"
	"net/url"
	"time"

	"github.com/gofiber/fiber/v2"
)

// WebhookRequest defines the expected JSON body for the POST request.
type WebhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// WebhookResponse defines the JSON response returned to the client.
type WebhookResponse struct {
	Success bool   `json:"success"`
	Message string `json:"message"`
}

// configuredWebhookURL is a simple in‑memory store for the webhook URL.
// In a real application you would persist this to a database or config file.
var configuredWebhookURL string

// ConfigureWebhook handles POST requests to configure a webhook.
// It validates the supplied webhook_url, performs a test GET request with a
// 3‑second timeout, and saves the URL if the test succeeds.
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse JSON body
	var req WebhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "Invalid JSON body",
		})
	}

	// Validate presence of webhook_url
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "webhook_url is required",
		})
	}

	// Parse and validate the URL
	parsedURL, err := url.Parse(req.WebhookURL)
	if err != nil || parsedURL.Scheme == "" || parsedURL.Host == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "Invalid webhook URL format",
		})
	}

	// Ensure the scheme is http or https
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "URL must use http or https scheme",
		})
	}

	// Test the webhook URL with a GET request and a 3‑second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusInternalServerError).JSON(WebhookResponse{
			Success: false,
			Message: fmt.Sprintf("Failed to reach webhook URL: %v", err),
		})
	}
	defer resp.Body.Close()

	// Optionally, you could require a 2xx status code:
	// if resp.StatusCode < 200 || resp.StatusCode >= 300 { ... }

	// Save the configuration (in‑memory for demonstration)
	configuredWebhookURL = req.WebhookURL

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(WebhookResponse{
		Success: true,
		Message: "Webhook configured successfully",
	})
}

func main() {
	// Initialize Fiber app
	app := fiber.New()

	// Define route for webhook configuration
	app.Post("/webhook", ConfigureWebhook)

	// Start the server on port 8080
	log.Fatal(app.Listen(":8080"))
}

