	// Return a success response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success": true,
		"message": "Webhook configured successfully",
	})
}

// isIPAllowed checks whether an IP address is publicly reachable.
// It returns false for loopback, private, link‑local, and other internal addresses.
func isIPAllowed(ip net.IP) bool {
	if ip == nil {
		return false
	}
	// Reject loopback (127.x.x.x, ::1)
	if ip.IsLoopback() {
		return false
	}
	// Reject private address ranges (RFC 1918, IPv6 unique local)
	if ip.IsPrivate() {
		return false
	}
	// Reject link‑local (169.254.0.0/16)
	if len(ip) == 4 && ip[0] == 169 && ip[1] == 254 {
		return false
	}
	// Reject IPv6 link‑local (fe80::/10)
	if len(ip) == 16 && ip[0] == 0xfe && ip[1] == 0x80 {
		return false
	}
	return true
}

// main sets up the Fiber router (example)
func main() {
	app := fiber.New()

	// Endpoint to configure webhook
	app.Post("/webhook/configure", ConfigureWebhook)

	// Start server
	fmt.Println("Server listening on :8080")
	if err := app.Listen(":8080"); err != nil {
		fmt.Printf("Error starting server: %v\n", err)
	}
}

