	"github.com/gofiber/fiber/v2"
)

// Config represents the incoming JSON body.
type Config struct {
	WebhookURL string `json:"webhook_url"`
}

// Response is used for JSON responses.
type Response struct {
	Success bool   `json:"success"`
	Message string `json:"message"`
}

// currentConfig holds the saved webhook configuration in memory.
var currentConfig *Config

// ConfigureWebhook handles POST requests with a JSON body containing webhook_url.
// It validates the URL by performing a GET request with a 3‑second timeout,
// saves the configuration and returns a JSON result.
func ConfigureWebhook(ctx *fiber.Ctx) error {
	var cfg Config

	// Parse JSON body
	if err := json.Unmarshal(ctx.Body(), &cfg); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "invalid JSON",
		})
	}

	// Validate presence of webhook_url
	if cfg.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "webhook_url is required",
		})
	}

	// Validate URL format
	if _, err := url.Parse(cfg.WebhookURL); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "invalid URL format",
		})
	}

	// Create HTTP client with 3‑second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Perform test GET request
	resp, err := client.Get(cfg.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadGateway).JSON(Response{
			Success: false,
			Message: "failed to reach webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Check for successful HTTP status (2xx)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadGateway).JSON(Response{
			Success: false,
			Message: "webhook URL returned non‑2xx status: " + resp.Status,
		})
	}

	// Save configuration (in‑memory)
	currentConfig = &cfg

	return ctx.JSON(Response{
		Success: true,
		Message: "webhook configured successfully",
	})
}

func main() {
	// Initialize Fiber app
	app := fiber.New()

	// Register route
	app.Post("/webhook/configure", ConfigureWebhook)

	// Start server on port 3000
	log.Fatal(app.Listen(":3000"))
}

