import (
	"log"
	"net/http"
	"net/url"
	"sync"
	"time"

	"github.com/gofiber/fiber/v2"
)

// In‑memory storage for the configured webhook URL
var (
	configuredURL   string
	configuredMutex sync.Mutex
)

// WebhookRequest represents the JSON body of the POST request
type WebhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// ConfigureWebhook handles POST requests with a JSON body containing webhook_url.
// It validates the URL by sending a GET request (3 s timeout), saves the configuration
// and returns a JSON response indicating success or failure.
func ConfigureWebhook(ctx *fiber.Ctx) error {
	var req WebhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "Invalid request body",
		})
	}

	rawURL := req.WebhookURL
	if rawURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "webhook_url is required",
		})
	}

	// Normalize URL: add http:// scheme if missing
	parsedURL, err := url.Parse(rawURL)
	if err != nil || parsedURL.Scheme == "" {
		parsedURL, err = url.Parse("http://" + rawURL)
		if err != nil {
			return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
				"error": "Invalid URL format",
			})
		}
	}

	// Validate the webhook URL by sending a GET request with a 3‑second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}
	resp, err := client.Get(parsedURL.String())
	if err != nil {
		return ctx.Status(fiber.StatusInternalServerError).JSON(fiber.Map{
			"error":   "Failed to reach webhook URL",
			"details": err.Error(),
		})
	}
	defer resp.Body.Close()

	// Consider any 2xx response as success; otherwise treat as validation failure
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error":  "Webhook URL returned non‑2xx status",
			"status": resp.StatusCode,
		})
	}

	// Save the configuration (in‑memory)
	configuredMutex.Lock()
	configuredURL = parsedURL.String()
	configuredMutex.Unlock()

	return ctx.JSON(fiber.Map{
		"success": true,
		"message": "Webhook configured successfully",
		"url":     configuredURL,
	})
}

func main() {
	app := fiber.New()

	// Define the route for configuring the webhook
	app.Post("/webhook/configure", ConfigureWebhook)

	// Start the Fiber server on port 3000
	log.Fatal(app.Listen(":3000"))
}

