package main

import (
	"fmt"
	"net/http"
	"net/url"
	"time"

	"github.com/gofiber/fiber/v2"
)

// WebhookConfig represents the JSON payload sent in the POST request.
type WebhookConfig struct {
	WebhookURL string `json:"webhook_url"`
}

// Response is the standard JSON response returned to the client.
type Response struct {
	Status  string `json:"status"`
	Message string `json:"message"`
}

// savedWebhookURL holds the latest configured webhook URL (in‑memory storage).
var savedWebhookURL string

// ConfigureWebhook handles a POST request containing a webhook_url.
// It validates the URL by performing a GET request with a 3‑second timeout,
// saves the configuration, and returns a JSON result.
func ConfigureWebhook(ctx *fiber.Ctx) error {
	var req WebhookConfig
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Status:  "error",
			Message: "Invalid request body",
		})
	}

	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Status:  "error",
			Message: "webhook_url is required",
		})
	}

	// Validate URL format.
	parsedURL, err := url.Parse(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Status:  "error",
			Message: "Invalid URL",
		})
	}
	if parsedURL.Scheme == "" || parsedURL.Host == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Status:  "error",
			Message: "URL must include a scheme (http/https) and host",
		})
	}

	// Send a GET request to the webhook URL with a 3‑second timeout.
	client := &http.Client{
		Timeout: 3 * time.Second,
	}
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Status:  "error",
			Message: "Failed to reach webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Consider any non‑2xx status as a validation failure.
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Status:  "error",
			Message: fmt.Sprintf("Webhook URL returned status %d", resp.StatusCode),
		})
	}

	// Save the configuration (in‑memory).
	savedWebhookURL = req.WebhookURL

	return ctx.JSON(Response{
		Status:  "success",
		Message: "Webhook configured successfully",
	})
}

func main() {
	app := fiber.New()

	// Route for configuring the webhook.
	app.Post("/webhook/configure", ConfigureWebhook)

	// Start the server on port 3000.
	app.Listen(":3000")
}

