package main

import (
	"fmt"
	"net/http"
	"time"

	"github.com/gofiber/fiber/v2"
)

// Config represents the webhook configuration request body
type Config struct {
	WebhookURL string `json:"webhook_url"`
}

// Response represents the API response
type Response struct {
	Success bool   `json:"success"`
	Message string `json:"message"`
}

// webhookConfig stores the configured webhook URL (in-memory storage)
var webhookConfig *Config

// ConfigureWebhook handles POST requests to configure webhook URL
// It validates the webhook by sending a GET request with 3 second timeout
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse the request body
	var config Config
	if err := ctx.BodyParser(&config); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "Invalid request body",
		})
	}

	// Validate webhook_url is provided
	if config.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "webhook_url is required",
		})
	}

	// Validate the webhook URL by sending a GET request with 3 second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(config.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: fmt.Sprintf("Failed to validate webhook URL: %v", err),
		})
	}
	defer resp.Body.Close()

	// Check for non-2xx status codes
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: fmt.Sprintf("Webhook URL returned invalid status code: %d", resp.StatusCode),
		})
	}

	// Save the configuration
	webhookConfig = &config

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(Response{
		Success: true,
		Message: "Webhook configured successfully",
	})
}

func main() {
	// Create new Fiber app
	app := fiber.New()

	// Define POST route for webhook configuration
	app.Post("/webhook/configure", ConfigureWebhook)

	// Start the server
	app.Listen(":3000")
}

