package main

import (
	"log"
	"net/http"
	"time"

	"github.com/gofiber/fiber/v2"
)

// Config holds the current webhook configuration.
type Config struct {
	WebhookURL string `json:"webhook_url"`
}

// httpClient is a global HTTP client with a 3‑second timeout.
var httpClient = &http.Client{
	Timeout: 3 * time.Second,
}

// global configuration storage (in‑memory for this example)
var config Config

// ConfigureWebhook handles POST requests to configure the webhook.
// Expected JSON body: {"webhook_url": "https://example.com/webhook"}
func ConfigureWebhook(ctx *fiber.Ctx) error {
	type requestBody struct {
		WebhookURL string `json:"webhook_url"`
	}

	var req requestBody
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid request body",
		})
	}

	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url is required",
		})
	}

	// Validate the webhook URL by sending a GET request with a 3‑second timeout.
	resp, err := httpClient.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Failed to reach webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	if resp.StatusCode >= 400 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Webhook URL returned an error status: " + resp.Status,
		})
	}

	// Save the configuration (in‑memory for this example).
	config = Config{WebhookURL: req.WebhookURL}

	return ctx.JSON(fiber.Map{
		"success": true,
		"message": "Webhook configured successfully",
	})
}

func main() {
	app := fiber.New()

	// POST /webhook – configures the webhook URL.
	app.Post("/webhook", ConfigureWebhook)

	// Start the server on port 3000.
	log.Fatal(app.Listen(":3000"))
}

