import (
	"fmt"
	"net"
	"net/http"
	"net/url"
	"sync"
	"time"

	"github.com/gofiber/fiber/v2"
)

// webhookRequest represents the JSON request body.
type webhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

var (
	configuredWebhookURL string
	webhookMutex         sync.Mutex
)

// isPublicIP checks if an IP address is not private, loopback, link‑local or multicast.
func isPublicIP(ip net.IP) bool {
	return !(ip.IsLoopback() || ip.IsPrivate() || ip.IsLinkLocalUnicast() || ip.IsMulticast())
}

// validateWebhookURL ensures that the host resolves to a public IP address.
func validateWebhookURL(rawURL string) error {
	parsedURL, err := url.Parse(rawURL)
	if err != nil {
		return fmt.Errorf("invalid URL: %w", err)
	}

	// Only allow http and https schemes.
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return fmt.Errorf("scheme must be http or https")
	}

	host := parsedURL.Hostname()
	if host == "" {
		return fmt.Errorf("host is missing")
	}

	// Resolve the hostname to IP addresses.
	ips, err := net.LookupHost(host)
	if err != nil {
		return fmt.Errorf("cannot resolve host: %w", err)
	}

	// Ensure at least one IP is public and none are private/reserved.
	for _, ipStr := range ips {
		ip := net.ParseIP(ipStr)
		if ip == nil {
			continue
		}
		if !isPublicIP(ip) {
			return fmt.Errorf("host resolves to a private or reserved IP address")
		}
	}

	return nil
}

// ConfigureWebhook handles POST requests to configure a webhook URL.
// It validates the URL, sends a GET test request, and saves the configuration.
func ConfigureWebhook(ctx *fiber.Ctx) error {
	var req webhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid JSON format",
		})
	}

	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url is required",
		})
	}

	// Security: validate that the URL points to a publicly reachable host.
	if err := validateWebhookURL(req.WebhookURL); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid webhook URL: " + err.Error(),
		})
	}

	// HTTP client with a short timeout.
	client := &http.Client{
		Timeout: 5 * time.Second,
	}

	// Send a GET request to test the webhook.
	httpReq, err := http.NewRequestWithContext(ctx.Context(), http.MethodGet, req.WebhookURL, nil)
	if err != nil {
		return ctx.Status(fiber.StatusInternalServerError).JSON(fiber.Map{
			"success": false,
			"error":   "Failed to create request",
		})
	}
	httpReq.Header.Set("Accept", "application/json")

	resp, err := client.Do(httpReq)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Failed to send test request: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Accept only 2xx responses.
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Webhook test returned status %d", resp.StatusCode),
		})
	}

	// Save the webhook URL (thread‑safe).
	webhookMutex.Lock()
	configuredWebhookURL = req.WebhookURL
	webhookMutex.Unlock()

	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success": true,
		"message": "Webhook configured successfully",
	})
}

// main sets up the Fiber router and starts the server.
func main() {
	app := fiber.New()

	// POST /webhook - configure webhook URL.
	app.Post("/webhook", ConfigureWebhook)

	// Listen on port 3000.
	if err := app.Listen(":3000"); err != nil {
		panic(err)
	}
}

