package main

import (
	"fmt"
	"net/http"
	"net/url"
	"time"

	"github.com/gofiber/fiber/v2"
)

// Config holds the currently saved webhook configuration.
var Config struct {
	WebhookURL string
	SavedAt    time.Time
}

// RequestBody represents the JSON payload expected for the POST request.
type RequestBody struct {
	WebhookURL string `json:"webhook_url"`
}

// Response represents the JSON response returned to the client.
type Response struct {
	Success    bool   `json:"success"`
	Message    string `json:"message"`
	WebhookURL string `json:"webhook_url,omitempty"`
}

// ConfigureWebhook handles the POST request to configure a webhook.
// It validates the provided URL by sending a GET request with a 3‑second timeout,
// saves the configuration and returns a JSON result.
func ConfigureWebhook(ctx *fiber.Ctx) error {
	var req RequestBody
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "Invalid JSON body",
		})
	}

	// Validate presence of webhook_url
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "webhook_url is required",
		})
	}

	// Validate URL format
	parsedURL, err := url.Parse(req.WebhookURL)
	if err != nil || parsedURL.Scheme == "" || parsedURL.Host == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "Invalid webhook_url format",
		})
	}

	// Only allow http and https schemes
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "URL must use http or https scheme",
		})
	}

	// Test the webhook URL with a GET request and a 3‑second timeout
	httpClient := &http.Client{
		Timeout: 3 * time.Second,
	}
	resp, err := httpClient.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadGateway).JSON(Response{
			Success: false,
			Message: fmt.Sprintf("Failed to reach webhook URL: %v", err),
		})
	}
	defer resp.Body.Close()

	// Consider any 2xx response as valid; otherwise treat as invalid
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadGateway).JSON(Response{
			Success: false,
			Message: fmt.Sprintf("Webhook URL returned non‑2xx status: %d", resp.StatusCode),
		})
	}

	// Save configuration (in‑memory for this example)
	Config.WebhookURL = req.WebhookURL
	Config.SavedAt = time.Now()

	return ctx.JSON(Response{
		Success:    true,
		Message:    "Webhook configured successfully",
		WebhookURL: Config.WebhookURL,
	})
}

func main() {
	// Initialize Fiber app
	app := fiber.New()

	// Route for webhook configuration
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start the server on port 8080
	fmt.Println("Server starting on :8080")
	if err := app.Listen(":8080"); err != nil {
		fmt.Printf("Error starting server: %v\n", err)
	}
}

