package main

import (
	"encoding/json"
	"fmt"
	"log"
	"net/http"
	"net/url"
	"time"

	"github.com/gofiber/fiber/v2"
)

// webhookURL holds the currently configured webhook URL (in‑memory storage).
var webhookURL string

// RequestBody represents the JSON payload received in the POST request.
type RequestBody struct {
	WebhookURL string `json:"webhook_url"`
}

// Response represents the JSON response sent back to the client.
type Response struct {
	Success bool   `json:"success"`
	Message string `json:"message"`
}

// ConfigureWebhook handles POST requests to configure a webhook.
// It validates the supplied URL by sending a GET request with a 3‑second timeout,
// then saves the configuration in memory.
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse JSON body
	var req RequestBody
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "Invalid JSON body",
		})
	}

	// Validate presence of webhook_url
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "webhook_url is required",
		})
	}

	// Validate URL format (must be absolute http/https)
	if _, err := parseWebhookURL(req.WebhookURL); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "Invalid webhook URL: " + err.Error(),
		})
	}

	// Create HTTP client with a 3‑second timeout
	httpClient := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send a test GET request to the webhook URL
	resp, err := httpClient.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusInternalServerError).JSON(Response{
			Success: false,
			Message: "Failed to reach webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Reject non‑2xx status codes
	if resp.StatusCode >= http.StatusBadRequest {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "Webhook URL returned error status: " + resp.Status,
		})
	}

	// Save configuration (in‑memory)
	webhookURL = req.WebhookURL

	// Return success response
	return ctx.JSON(Response{
		Success: true,
		Message: "Webhook configured successfully",
	})
}

// parseWebhookURL checks that the given string is a valid absolute HTTP/HTTPS URL.
func parseWebhookURL(rawURL string) (*url.URL, error) {
	u, err := url.Parse(rawURL)
	if err != nil {
		return nil, err
	}
	if !u.IsAbs() {
		return nil, fmt.Errorf("URL is not absolute")
	}
	if u.Scheme != "http" && u.Scheme != "https" {
		return nil, fmt.Errorf("URL scheme must be http or https")
	}
	return u, nil
}

func main() {
	// Initialize Fiber app
	app := fiber.New()

	// Define POST route for webhook configuration
	app.Post("/webhook/configure", ConfigureWebhook)

	// Start the HTTP server on port 8080
	log.Fatal(app.Listen(":8080"))
}

