// parseCIDR parses a CIDR notation string and returns an *net.IPNet
func parseCIDR(cidr string) *net.IPNet {
	_, ipNet, err := net.ParseCIDR(cidr)
	if err != nil {
		return &net.IPNet{}
	}
	return ipNet
}

// isPrivateIP checks if an IP address is private/reserved
func isPrivateIP(ipStr string) bool {
	ip := net.ParseIP(ipStr)
	if ip == nil {
		return false
	}

	for _, network := range privateIPRanges {
		if network.Contains(ip) {
			return true
		}
	}

	return false
}

// validateHostname validates that the hostname is not an internal/private address
func validateHostname(hostname string) error {
	// Check for localhost variants
	hostnameLower := strings.ToLower(hostname)
	if hostnameLower == "localhost" || hostnameLower == "localhost.localdomain" {
		return fmt.Errorf("localhost is not allowed")
	}

	// Check if hostname is an IP address directly
	if isPrivateIP(hostname) {
		return fmt.Errorf("private IP addresses are not allowed: %s", hostname)
	}

	// Resolve hostname to IP addresses
	ips, err := net.LookupIP(hostname)
	if err != nil {
		// If DNS lookup fails, reject the request for security
		return fmt.Errorf("failed to resolve hostname: %w", err)
	}

	// Check all resolved IPs
	for _, ip := range ips {
		if isPrivateIP(ip.String()) {
			return fmt.Errorf("hostname resolves to private IP: %s", ip.String())
		}
	}

	return nil
}

