// isPrivateIP returns true if the IP address belongs to a private or reserved range.
func isPrivateIP(ip net.IP) bool {
	if ip == nil {
		return false
	}
	// Loopback addresses (127.0.0.0/8)
	if ip.IsLoopback() {
		return true
	}
	// 10.0.0.0/8
	if ip[0] == 10 {
		return true
	}
	// 172.16.0.0/12
	if ip[0] == 172 && ip[1] >= 16 && ip[1] <= 31 {
		return true
	}
	// 192.168.0.0/16
	if ip[0] == 192 && ip[1] == 168 {
