	if ip[0] == 169 && ip[1] == 254 {
		return true
	}
	// 100.64.0.0/10 (Carrier‑Grade NAT)
	if ip[0] == 100 && ip[1] >= 64 && ip[1] <= 127 {
		return true
	}
	// Add any other reserved ranges as needed
	return false
}

