package main

import (
	"log"
	"net/http"
	"net/url"
	"time"

	"github.com/gofiber/fiber/v2"
)

// Request body structure for configuring a webhook
type WebhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// Global variable to store the configured webhook URL
var configuredWebhookURL string

// ConfigureWebhook handles POST requests with a JSON body containing webhook_url.
// It validates the URL by performing a GET request with a 3‑second timeout,
// saves the configuration, and returns a JSON response.
func ConfigureWebhook(ctx *fiber.Ctx) error {
	var req WebhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "Invalid JSON body",
		})
	}

	// Validate presence of webhook_url
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "webhook_url is required",
		})
	}

	// Validate URL format
	parsedURL, err := url.Parse(req.WebhookURL)
	if err != nil || parsedURL.Scheme == "" || parsedURL.Host == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "Invalid URL format",
		})
	}

	// Test the webhook URL with a GET request and a 3‑second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "Failed to reach webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Save the configuration
	configuredWebhookURL = req.WebhookURL

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"message":     "Webhook configured successfully",
		"webhook_url": configuredWebhookURL,
	})
}

func main() {
	app := fiber.New()

	// POST route to configure webhook
	app.Post("/webhook/configure", ConfigureWebhook)

	// Start the server on port 8080
	log.Fatal(app.Listen(":8080"))
}

