package main

import (
	"encoding/json"
	"log"
	"net/http"
	"net/url"
	"time"

	"github.com/gofiber/fiber/v2"
)

// Config holds the current webhook configuration.
var config struct {
	WebhookURL string
}

// ConfigureWebhook handles POST requests with a JSON body containing webhook_url.
// It validates the URL by sending a GET request with a 3‑second timeout,
// saves the configuration if validation succeeds, and returns a JSON response.
func ConfigureWebhook(ctx *fiber.Ctx) error {
	var req struct {
		WebhookURL string `json:"webhook_url"`
	}

	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": "Invalid request body",
		})
	}

	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": "webhook_url is required",
		})
	}

	// Basic URL validation.
	if _, err := url.ParseRequestURI(req.WebhookURL); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": "Invalid webhook URL",
		})
	}

	// Send a test GET request with a 3‑second timeout.
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": "Failed to reach webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Consider any 2xx status as success.
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": "Webhook URL returned non‑2xx status: " + resp.Status,
		})
	}

	// Save the configuration.
	config.WebhookURL = req.WebhookURL

	return ctx.JSON(fiber.Map{
		"status":  "success",
		"message": "Webhook configured successfully",
	})
}

func main() {
	app := fiber.New()

	// Register the webhook configuration endpoint.
	app.Post("/webhook", ConfigureWebhook)

	// Start the Fiber server on port 3000.
	log.Fatal(app.Listen(":3000"))
}

